import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:flutter/material.dart';

class ApiClient {
  final String baseUrl;
  String? token;

  ApiClient(this.baseUrl);

  Future<void> authenticate(String username, String password) async {
    final response = await http.post(
      Uri.parse('$baseUrl/auth/login'),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({'username': username, 'password': password}),
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      token = data['token'];
    } else {
      throw Exception('Failed to authenticate');
    }
  }

  Future<Map<String, dynamic>> getUserProfile() async {
    final response = await http.get(
      Uri.parse('$baseUrl/user/profile'),
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer $token',
      },
    );

    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception('Failed to load user profile');
    }
  }

  Future<void> synchronizeData(Map<String, dynamic> data) async {
    final response = await http.post(
      Uri.parse('$baseUrl/data/sync'),
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer $token',
      },
      body: jsonEncode(data),
    );

    if (response.statusCode != 200) {
      throw Exception('Failed to synchronize data');
    }
  }
}

class MyApp extends StatelessWidget {
  final ApiClient apiClient = ApiClient('https://api.example.com');

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter HTTP Client',
      home: Scaffold(
        appBar: AppBar(title: Text('HTTP Client')),
        body: Center(
          child: ElevatedButton(
            onPressed: () async {
              try {
                await apiClient.authenticate('user', 'pass');
                final profile = await apiClient.getUserProfile();
                print(profile);
                await apiClient.synchronizeData({'example': 'data'});
              } catch (e) {
                print(e.toString());
              }
            },
            child: Text('Fetch Data'),
          ),
        ),
      ),
    );
  }
}

void main() {
  runApp(MyApp());
